<template>
  <div class="widget-card">
    <loader :is-visible="isLoading"></loader>
    <div class="widget-header">
      <div class="widget-title">
        <i class="fas fa-users"></i> Top 20 Customers by Revenue
      </div>
    </div>

    <div class="sort-controls">
      <button v-for="sort in sortOptions" :key="sort.id" :class="['sort-btn', { active: selectedSort === sort.id }]"
        @click="selectSort(sort)">
        {{ sort.label }}
      </button>
    </div>


    <div class="table-container">
      <table class="top-customers-table">
        <thead>
          <tr>
            <th>Rank</th>
            <th>Customer</th>
            <th>Revenue</th>
            <th>YoY Growth</th>
          </tr>
        </thead>
        <tbody>
          <tr v-for="(customer, index) in customers" :key="index">
            <td>{{ index + 1 }}</td>
            <td>{{ customer.name }}</td>
            <td>{{ formatCurrency(customer.revenue) }}</td>
            <td>{{ formatPercent(customer.growth) }}</td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</template>

<script>
import { analyticsService } from '../../../../services/analyticsService';

export default {
  name: 'TopCustomersWidget',
  data() {
    return {

      customers: [],
      sortField: 'Growth_Percentage',
      selectedSort: 'growth_desc',
      sortOrder: 'desc',
      sortOptions: [
        { id: 'revenue_desc', label: 'Sort by Revenue (High to Low)', name: 'Current_Revenue' },
        { id: 'revenue_asc', label: 'Sort by Revenue (Low to High)', name: 'Current_Revenue' },
        { id: 'growth_desc', label: 'Sort by Growth (High to Low)', name: 'Growth_Percentage' },
        { id: 'growth_asc', label: 'Sort by Growth (Low to High)', name: 'Growth_Percentage' },
        { id: 'ClientName', label: 'Sort by Name (A-Z)', name: 'ClientName' }
      ],
      isLoading: false,
    };
  },
  mounted() {
    this.loadData();
  },

  methods: {
    async loadData() {

      this.isLoading = true;

      try {
        //debugger;

        var PeriodType = '1_YEAR';
        const url = `PeriodType=${PeriodType}&SortColumn=${this.sortField}&SortDirection=${this.sortOrder}`;
        const response = await analyticsService.GetClientRevenueGrowth(url);
        if (response && response.data && response.data.result) {
          // Handle double-encoded JSON: result is a string containing an array with a JSON string
          let resultData = response.data.result;

          // First parse: convert string to array
          if (typeof resultData === 'string') {
            resultData = JSON.parse(resultData);
          }

          // Second parse: extract the JSON string from the array and parse it
          if (Array.isArray(resultData) && resultData.length > 0 && typeof resultData[0] === 'string') {
            resultData = JSON.parse(resultData[0]);
          }

          // Map the API response to the expected format
          this.customers = (Array.isArray(resultData) ? resultData : []).map(customer => ({
            name: customer.ClientName || '',
            revenue: customer.Current_Revenue || 0,
            growth: customer.Growth_Percentage || 0,
            previousRevenue: customer.Previous_Revenue || 0,
            revenueDifference: customer.Revenue_Difference || 0,
            growthTrend: customer.Growth_Trend || 'UP'
          }));
        }
      } catch (error) {
        console.error('Error loading top customers:', error);
      } finally {
        this.isLoading = false;
      }
    },
    selectSort(sort) {
      //debugger

      this.selectedSort = sort.id;
      this.sortField = sort.name;
      this.sortOrder = sort.id.includes('desc') ? 'desc' : 'asc';


      //this.selectedSort = name;
      this.loadData();
    },
    formatCurrency(value) {
      return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 0 }).format(value);
    },
    formatPercent(value) {
      return `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;
    }
  }
};
</script>

<style scoped>
.widget-card {
  background: white;
  border-radius: 10px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.05);
  padding: 25px;
  margin-bottom: 25px;
}

.widget-header {
  margin-bottom: 20px;
  padding-bottom: 15px;
  border-bottom: 1px solid #e1e8ed;
}

.widget-title {
  font-size: 20px;
  font-weight: 600;
  color: #003d4d;
  display: flex;
  align-items: center;
  gap: 10px;
}

.widget-title i {
  color: #006666;
}

.sort-controls {
  display: flex;
  gap: 10px;
  margin-bottom: 20px;
  flex-wrap: wrap;
}

.sort-btn {
  padding: 8px 16px;
  background: #f8fafc;
  border: 1px solid #e1e8ed;
  border-radius: 6px;
  cursor: pointer;
  transition: all 0.3s;
  color: #2c3e50;
  font-size: 14px;
}

.sort-btn:hover {
  background: #e6f2f2;
}

.sort-btn.active {
  background: #006666;
  color: white;
  border-color: #006666;
}

.table-container {
  overflow-x: auto;
}

.top-customers-table {
  width: 100%;
  border-collapse: collapse;
}

.top-customers-table thead {
  background: #f8fafc;
}

.top-customers-table th {
  padding: 12px;
  text-align: left;
  font-weight: 600;
  color: #003d4d;
  border-bottom: 2px solid #e1e8ed;
}

.top-customers-table td {
  padding: 12px;
  border-bottom: 1px solid #e1e8ed;
}

.top-customers-table tr:hover {
  background: #f8fafc;
}

.loading {
  text-align: center;
  padding: 40px;
  color: #7f8c8d;
}
</style>