<template>
    <div class="widget-card">
        <div class="widget-header">
            <div class="widget-title">
                <i class="fas fa-user-clock"></i> Flag Reason Report
            </div>
        </div>

        <div id="FlagReasonReport" class="chart-container"></div>


    </div>
</template>

<script>
import * as Plotly from 'plotly.js-dist';
import { analyticsService } from '../../../../services/analyticsService';

export default {
    name: 'AgentPerformance',
    data() {
        return {
            loading: false,
            FlagResonData: [],
            FlagReason: [],
            FlagRecords: []
        };
    },

    mounted() {
        var vm = this;
        vm.loadData();
    },
    methods: {
        async loadData() {

            var vm = this;
            vm.loading = true;
            try {

                const response = await analyticsService.GetFlagReasonData();
                if (response && response.data && response.data.result) {

                    let result = response.data.result;

                    // 1️⃣ If result is a string, parse it
                    if (typeof result === 'string') {
                        result = JSON.parse(result);
                    }

                    // 2️⃣ Now result should be an array → take first item
                    if (Array.isArray(result) && typeof result[0] === 'string') {
                        result = JSON.parse(result[0]);
                    }

                    // 3️⃣ Now you finally have the object
                    const dataArray = result.Data || [];

                    vm.FlagResonData = dataArray;

                    vm.FlagReason = vm.FlagResonData.map(item => item.flag_reason);
                    vm.FlagRecords = vm.FlagResonData.map(item => item.FlagRecords);

                    vm.drawChart();

                }

            } catch (error) {
                console.error('Error loading total revenue trend:', error);
            } finally {
                vm.loading = false;
            }
        },
        drawChart() {

            const trace = {
                x: this.FlagReason,
                y: this.FlagRecords,
                type: 'bar',
                text: this.FlagRecords.map(v => v.toLocaleString()),
                textposition: 'outside',
                textfont: {
                    size: 12,
                    color: '#0e0d0d'
                },
                marker: { color: '#003f5c' }
            };

            const layout = {
                margin: { t: 30, b: 100, l: 50, r: 30 },
                //uniformtext: { minsize: 10, mode: 'hide' },
                paper_bgcolor: 'transparent',
                plot_bgcolor: 'transparent',
                height: 600
            };

            Plotly.newPlot('FlagReasonReport', [trace], layout, { responsive: true });
        }
    }
};
</script>

<style scoped>
.widget-card {
    background: white;
    border-radius: 10px;
    box-shadow: 0 4px 6px rgba(0, 0, 0, 0.05);
    padding: 20px;
    margin-bottom: 25px;
}

.widget-header {
    margin-bottom: 15px;
}

.widget-title {
    font-size: 16px;
    font-weight: 600;
    color: #003d4d;
    display: flex;
    align-items: center;
    gap: 8px;
}

.widget-title i {
    color: #006666;
}

.chart-container {
    min-height: 400px;
    width: 100%;
}

.loading {
    text-align: center;
    padding: 40px;
    color: #7f8c8d;
}
</style>
